# After: lazy generator
from collections.abc import Iterator

def get_error_lines(path: str) -> Iterator[str]:
    with open(path) as f:
        for line in f:
            if "ERROR" in line:
                yield line.rstrip()
                # file handle stays open between yields and closes on exhaustion
                # or when the generator is garbage-collected

def open_lines(path: str) -> Iterator[str]:
    with open(path) as f:
        yield from f               # delegate to file's own iterator

def filter_level(lines: Iterator[str], level: str) -> Iterator[str]:
    for line in lines:
        if level in line:
            yield line.rstrip()

def parse_json_field(lines: Iterator[str], field: str) -> Iterator[str]:
    import json
    for line in lines:
        try:
            yield json.loads(line)[field]
        except (json.JSONDecodeError, KeyError):
            pass                   # silently skip malformed lines

# Compose without materializing any intermediate list
pipeline = parse_json_field(
    filter_level(open_lines("/var/log/agent.jsonl"), "ERROR"),
    "message"
)

for msg in pipeline:
    alert_oncall(msg)

from collections.abc import Iterator, Generator

def token_stream(text: str) -> Iterator[str]:
    for word in text.split():
        yield word

def accumulator() -> Generator[int, int, str]:
    """Yields running total, accepts increments via send(), returns summary."""
    total = 0
    while True:
        increment = yield total
        if increment is None:
            return f"Final total: {total}"
        total += increment

import time
from collections.abc import Iterator
from typing import Any

def paginate(
    fetch_fn,            # callable(page: int, page_size: int) -> list[Any]
    page_size: int = 50,
    max_retries: int = 3,
    backoff: float = 1.0,
) -> Iterator[Any]:
    """
    Lazily yield all items from a paginated API endpoint.
    Retries transient HTTP errors with exponential back-off.
    Stops when a page returns fewer items than page_size.
    """
    page = 1
    while True:
        for attempt in range(max_retries):
            try:
                batch = fetch_fn(page=page, page_size=page_size)
                break
            except TransientError:
                if attempt == max_retries - 1:
                    raise
                time.sleep(backoff * 2 ** attempt)
        if not batch:
            return                 # empty page signals end of results
        yield from batch
        if len(batch) < page_size:
            return                 # last partial page
        page += 1

# Usage — consumer never sees pagination
for document in paginate(lambda **kw: api.search(query="agent", **kw)):
    index_document(document)

