from itertools import batched
from collections.abc import Iterator

def embed_in_batches(texts: Iterator[str], batch_size: int = 32) -> Iterator[list[str]]:
    """Collect texts into batches before calling the embedding API."""
    for batch in batched(texts, batch_size):
        yield list(batch)   # send batch to GPU embedding model

# Earlier Python — manual batching
def chunked(it: Iterator, n: int) -> Iterator[list]:
    buf = []
    for item in it:
        buf.append(item)
        if len(buf) == n:
            yield buf
            buf = []
    if buf:
        yield buf

import contextlib

def safe_file_lines(path: str) -> Iterator[str]:
    """Guarantees the file is closed even if the caller breaks early."""
    with open(path) as f:          # `with` block's __exit__ called on .close()
        for line in f:
            yield line

# The generator's close() propagates GeneratorExit into the body,
# which triggers the `with` statement's __exit__, closing the file.
gen = safe_file_lines("/var/log/agent.log")
for line in gen:
    if "CRITICAL" in line:
        break                      # generator.close() called by CPython GC
                                   # (or explicitly here: gen.close())
